def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 2:
            score -= 100 * (ratio - 2)**2
        elif ratio > 1:
            score -= 20 * (ratio - 1)
        else:
            for k in range(1, 6):
                if ratio < k * 0.2:
                    score += (k ** 2) / (k * 0.2 - ratio + 1e-10)
                    break
            else:
                score += 5 * (1 - ratio)
        penalty = 0
        for x in range(1, 4):
            penalty += ((-1) ** x) * (ratio ** (2 * x)) / (x * 2)
        score += penalty
        if item > capacity:
            score -= 70
            for m in range(3):
                if capacity == 0:
                    break
                score += (item % (capacity + 1)) / (m + 1)
        elif (capacity - item) < 0.1 * capacity:
            score += 15
        else:
            if ratio < 0.3:
                score -= 5 * np.exp(-ratio*10)
        priorities[i] = score
    max_priority = np.max(priorities[np.isfinite(priorities)])
    if max_priority > 0:
        priorities = np.where(np.isfinite(priorities), priorities / max_priority, -np.inf)
    return priorities
